def profile_rows(rows: list[dict]) -> dict:
    if not rows:
        return {'rows': 0, 'missing': 0, 'duplicates': 0}
    missing = sum(v in (None, '') for row in rows for v in row.values())
    signatures = [tuple(sorted(row.items())) for row in rows]
    return {'rows': len(rows), 'missing': missing, 'duplicates': len(signatures)-len(set(signatures))}

