from dataclasses import dataclass, asdict

@dataclass
class Metric:
    name: str
    value: float

metrics=[]

def health():
    return {'status':'ok'}

def create_metric(name: str, value: float):
    metric=Metric(name,float(value)); metrics.append(metric); return asdict(metric)

